// ────────────────────── AUDIO ENGINE ──────────────────────

class AudioEngine {
  private ctx: AudioContext | null = null;
  masterVol = 0.8; sfxVol = 0.8; musicVol = 0.6;
  private masterGain: GainNode | null = null;
  private sfxGain: GainNode | null = null;
  private musicGain: GainNode | null = null;
  private droneOscs: OscillatorNode[] = [];

  init() {
    if (this.ctx) return;
    this.ctx = new AudioContext();
    this.masterGain = this.ctx.createGain();
    this.masterGain.gain.value = this.masterVol;
    this.masterGain.connect(this.ctx.destination);
    this.sfxGain = this.ctx.createGain();
    this.sfxGain.gain.value = this.sfxVol;
    this.sfxGain.connect(this.masterGain);
    this.musicGain = this.ctx.createGain();
    this.musicGain.gain.value = this.musicVol;
    this.musicGain.connect(this.masterGain);
  }

  setVolumes(master: number, sfx: number, music: number) {
    this.masterVol = master; this.sfxVol = sfx; this.musicVol = music;
    if (this.masterGain) this.masterGain.gain.value = master;
    if (this.sfxGain) this.sfxGain.gain.value = sfx;
    if (this.musicGain) this.musicGain.gain.value = music;
  }

  private tone(freq: number, type: OscillatorType, dur: number, vol = 0.3, dest?: GainNode) {
    if (!this.ctx || !this.sfxGain) return;
    const t = this.ctx.currentTime;
    const o = this.ctx.createOscillator();
    const g = this.ctx.createGain();
    o.type = type; o.frequency.value = freq * (0.95 + Math.random() * 0.1);
    g.gain.setValueAtTime(vol, t);
    g.gain.exponentialRampToValueAtTime(0.001, t + dur);
    o.connect(g).connect(dest || this.sfxGain);
    o.start(t); o.stop(t + dur);
  }

  gravitySwitch() { this.tone(440, 'triangle', 0.15, 0.25); this.tone(660, 'sine', 0.12, 0.2); }
  wallHit() { this.tone(180, 'square', 0.08, 0.2); }
  gemCollect() {
    if (!this.ctx) return;
    const t = this.ctx.currentTime;
    [660, 880, 1100, 1320].forEach((f, i) => {
      setTimeout(() => this.tone(f, 'sine', 0.2, 0.2), i * 60);
    });
  }
  hazardHit() { this.tone(120, 'sawtooth', 0.3, 0.3); this.tone(80, 'square', 0.4, 0.2); }
  goalReached() {
    [523, 659, 784, 1047, 1319].forEach((f, i) => {
      setTimeout(() => this.tone(f, 'sine', 0.3, 0.25), i * 80);
    });
  }
  portalEnter() { this.tone(880, 'sawtooth', 0.2, 0.15); this.tone(1320, 'triangle', 0.15, 0.15); }
  breakBlock() { this.tone(200, 'square', 0.15, 0.2); this.tone(150, 'sawtooth', 0.1, 0.15); }
  countdownTick() { this.tone(440, 'sine', 0.1, 0.2); }
  countdownGo() { this.tone(880, 'sine', 0.2, 0.3); }
  buttonClick() { this.tone(660, 'sine', 0.06, 0.15); }
  achievement() {
    [660, 784, 880, 1047, 1320].forEach((f, i) => {
      setTimeout(() => this.tone(f, 'sine', 0.25, 0.2), i * 70);
    });
  }
  gameOver() {
    [440, 349, 294, 220].forEach((f, i) => {
      setTimeout(() => this.tone(f, 'triangle', 0.3, 0.2), i * 100);
    });
  }
  gameStart() {
    [330, 440, 523, 660].forEach((f, i) => {
      setTimeout(() => this.tone(f, 'triangle', 0.15, 0.2), i * 70);
    });
  }
  levelUp() {
    [523, 659, 784, 1047, 1319, 1568].forEach((f, i) => {
      setTimeout(() => this.tone(f, 'sine', 0.2, 0.2), i * 60);
    });
  }

  startDrone() {
    if (!this.ctx || !this.musicGain || this.droneOscs.length > 0) return;
    const make = (freq: number, type: OscillatorType, vol: number) => {
      const o = this.ctx!.createOscillator();
      const g = this.ctx!.createGain();
      const f = this.ctx!.createBiquadFilter();
      o.type = type; o.frequency.value = freq;
      f.type = 'lowpass'; f.frequency.value = 400;
      g.gain.value = vol;
      o.connect(f).connect(g).connect(this.musicGain!);
      o.start();
      this.droneOscs.push(o);
    };
    make(55, 'sine', 0.08);
    make(82.5, 'triangle', 0.05);
    make(110, 'sine', 0.03);
    // LFO
    const lfo = this.ctx.createOscillator();
    const lfoG = this.ctx.createGain();
    lfo.type = 'sine'; lfo.frequency.value = 0.15;
    lfoG.gain.value = 0.02;
    if (this.droneOscs[0]) {
      lfo.connect(lfoG).connect(this.droneOscs[0].frequency);
    }
    lfo.start();
    this.droneOscs.push(lfo);
  }

  stopDrone() {
    this.droneOscs.forEach(o => { try { o.stop(); } catch {} });
    this.droneOscs = [];
  }
}

// ────────────────────── SAVE/LOAD ──────────────────────

function defaultSave(): SaveData {
  return {
    games: 0, clears: 0, totalScore: 0, bestScore: 0,
    totalGems: 0, totalMoves: 0, perfectLevels: 0, bestStreak: 0,
    playTime: 0, level: 1, xp: 0,
    achievements: [], skin: 0, theme: 0,
    levelStars: new Array(24).fill(0), levelBest: new Array(24).fill(0),
    masterVol: 0.8, sfxVol: 0.8, musicVol: 0.6,
    dailyDate: '', dailyBest: 0, dailyStreak: 0,
    leaderboard: [],
  };
}

function loadSave(): SaveData {
  try {
    const raw = localStorage.getItem('neon-gravity-save');
    if (raw) { const d = JSON.parse(raw); return { ...defaultSave(), ...d }; }
  } catch {}
  return defaultSave();
}

function saveSave(s: SaveData) {
  try { localStorage.setItem('neon-gravity-save', JSON.stringify(s)); } catch {}
}

// ────────────────────── PARTICLE SYSTEM ──────────────────────

interface Particle { mesh: Mesh; vx: number; vy: number; vz: number; life: number; maxLife: number; }

class ParticlePool {
  particles: Particle[] = [];
  private pool: Particle[] = [];
  private scene: any;

  constructor(scene: any, maxParticles = 150) {
    this.scene = scene;
    const geo = new SphereGeometry(0.008, 4, 4);
    for (let i = 0; i < maxParticles; i++) {
      const mat = new MeshBasicMaterial({ color: 0x00ffcc, transparent: true, blending: AdditiveBlending });
      const mesh = new Mesh(geo, mat);
      mesh.visible = false;
      scene.add(mesh);
      this.pool.push({ mesh, vx: 0, vy: 0, vz: 0, life: 0, maxLife: 0 });
    }
  }

  burst(x: number, y: number, z: number, count: number, color: string, spread = 0.8) {
    const c = new Color(color);
    for (let i = 0; i < count; i++) {
      const p = this.pool.pop();
      if (!p) break;
      p.mesh.position.set(x, y, z);
      (p.mesh.material as MeshBasicMaterial).color.copy(c);
      (p.mesh.material as MeshBasicMaterial).opacity = 1;
      p.mesh.visible = true;
      p.vx = (Math.random() - 0.5) * spread;
      p.vy = (Math.random() - 0.5) * spread;
      p.vz = (Math.random() - 0.5) * spread * 0.3;
      p.life = 0.6 + Math.random() * 0.4;
      p.maxLife = p.life;
      this.particles.push(p);
    }
  }

  update(dt: number) {
    for (let i = this.particles.length - 1; i >= 0; i--) {
      const p = this.particles[i];
      p.life -= dt;
      if (p.life <= 0) {
        p.mesh.visible = false;
        this.pool.push(p);
        this.particles.splice(i, 1);
        continue;
      }
      p.vy -= 1.5 * dt;
      p.mesh.position.x += p.vx * dt;
      p.mesh.position.y += p.vy * dt;
      p.mesh.position.z += p.vz * dt;
      (p.mesh.material as MeshBasicMaterial).opacity = p.life / p.maxLife;
    }
  }
}

// ────────────────────── SEEDED RNG ──────────────────────

function mulberry32(seed: number) {
  return () => {
    seed |= 0; seed = seed + 0x6D2B79F5 | 0;
    let t = Math.imul(seed ^ seed >>> 15, 1 | seed);
    t = t + Math.imul(t ^ t >>> 7, 61 | t) ^ t;
    return ((t ^ t >>> 14) >>> 0) / 4294967296;
  };
}

function dateSeed(): number {
  const d = new Date();
  return d.getFullYear() * 10000 + (d.getMonth() + 1) * 100 + d.getDate();
}

function generateRandomLevel(rng: () => number, size = 10): LevelDef {
  const grid: string[][] = [];
  for (let r = 0; r < size; r++) {
    grid.push([]);
    for (let c = 0; c < size; c++) {
      if (r === 0 || r === size - 1 || c === 0 || c === size - 1) grid[r].push('#');
      else grid[r].push('.');
    }
  }
  // Place start
  grid[1][1] = 'S';
  // Place goal
  grid[size - 2][size - 2] = 'G';
  // Place random walls
  const wallCount = Math.floor(size * 1.5 + rng() * size);
  for (let i = 0; i < wallCount; i++) {
    const r = 1 + Math.floor(rng() * (size - 2));
    const c = 1 + Math.floor(rng() * (size - 2));
    if (grid[r][c] === '.') grid[r][c] = '#';
  }
  // Place gems
  const gemCount = 2 + Math.floor(rng() * 4);
  for (let i = 0; i < gemCount; i++) {
    const r = 1 + Math.floor(rng() * (size - 2));
    const c = 1 + Math.floor(rng() * (size - 2));
    if (grid[r][c] === '.') grid[r][c] = '*';
  }
  // Place hazards
  const hazCount = 1 + Math.floor(rng() * 3);
  for (let i = 0; i < hazCount; i++) {
    const r = 1 + Math.floor(rng() * (size - 2));
    const c = 1 + Math.floor(rng() * (size - 2));
    if (grid[r][c] === '.') grid[r][c] = 'X';
  }
  return { name: 'Random', size, par: 8, grid: grid.map(row => row.join('')) };
}

